   const a = requireWasm();
   if (!a) { showToast('WASM not loaded', 'err'); return; }

+  // The WASM handle table is global (shared across runtimes), so absolute slot
+  // numbers differ between runs. What's deterministic is the RELATIVE allocation
+  // pattern: which offsets get reused, in what order, with what generation deltas.
+  // We normalize by subtracting each run's first-allocated slot to get offsets.
   function runSequence() {
     const rt = (a.runtimeCreate || a.runtime_create)();
     if (rt.outcome !== 'ok') return null;
     const results = [];
     const scopes = [];
+    let baseSlot = -1;
     // Create 5 scopes
     for (let i = 0; i < 5; i++) {
       const s = rt.value.enterScope('s' + i);
       if (s.outcome === 'ok') {
-        results.push({ op: 'create', label: 's' + i, slot: s.value.slot, gen: s.value.generation });
+        if (baseSlot < 0) baseSlot = s.value.slot;
+        results.push({ op: 'create', label: 's' + i, slot: s.value.slot - baseSlot, gen: s.value.generation });
         scopes.push(s.value);
       }
     }
     // Close first 3 (frees slots for reuse)
     for (let i = 0; i < 3; i++) {
       scopes[i].close();
-      results.push({ op: 'close', label: 's' + i, slot: scopes[i].slot });
+      results.push({ op: 'close', label: 's' + i, slot: scopes[i].slot - baseSlot });
     }
-    // Create 5 more (should reuse freed slots)
+    // Create 5 more (should reuse freed slots in LIFO order)
     for (let i = 5; i < 10; i++) {
       const s = rt.value.enterScope('s' + i);
       if (s.outcome === 'ok') {
-        results.push({ op: 'create', label: 's' + i, slot: s.value.slot, gen: s.value.generation });
+        results.push({ op: 'create', label: 's' + i, slot: s.value.slot - baseSlot, gen: s.value.generation });
         s.value.close();
       }
     }
     rt.value.close();
-    return results;
+    return { results, baseSlot };
   }

-  const run1 = runSequence();
-  const run2 = runSequence();
-  const match = JSON.stringify(run1) === JSON.stringify(run2);
+  const r1 = runSequence();
+  const r2 = runSequence();
+  const run1 = r1.results;
+  const run2 = r2.results;
+  // Compare the normalized patterns (relative slot offsets + generation deltas)
+  const pattern1 = run1.map(r => r.op + ':' + r.slot);
+  const pattern2 = run2.map(r => r.op + ':' + r.slot);
+  const match = JSON.stringify(pattern1) === JSON.stringify(pattern2);

